+        thread_id: 'vanishing-thread',
+        role: 'worker',
+        policy: 'workspace-write',
+        status: 'running',
+        updated_at: '2025-11-28T09:00:00Z',
+        controller_id: 'test-controller',
+      },
+    });
+
+    let pollCount = 0;
+    const sleep = vi.fn(async () => {
+      pollCount++;
+      if (pollCount === 2) {
+        // Thread disappears during wait (not archived, just gone)
