+      }
+      await new Promise((r) => setTimeout(r, 10));
+      return true;
+    });
+
+    const now = vi.fn();
+    now.mockReturnValueOnce(0);
+    now.mockReturnValue(5_000);
+
+    await expect(
+      waitCommand({
+        rootDir: codexRoot,
+        threadIds: ['vanishing-thread'],
+        controllerId: 'test-controller',
+        intervalMs: 50,
+        timeoutMs: 10_000,
+        sleep,
+        now,
+      })
+    ).rejects.toThrow(/disappeared|missing|unexpectedly/i);
